"""Corpus fidelity run: convert every corpus PDF with the browser engine,
render both sides, score structural similarity per page, report.

Two corpora, scored with the same render-diff metric but reported separately:

  * synthetic (docs/)        - generated by build_corpus.py, deterministic
  * real      (real/docs/)   - public real-world PDFs from build_real_corpus.py

Scores land in corpus_scores.json. The first run writes corpus_baseline.json;
later runs FAIL if any gated number regresses against the baseline:

  * synthetic median
  * real median
  * worst-page floor (the lowest single page score across both corpora)

This is the release gate recorded in SITE_SPEC.md section 0a.

Every run also writes tests/corpus/triage/: side-by-side PNGs (source page vs
converted render) for the 10 lowest-scoring pages, plus triage.json describing
the dominant differing regions per page. That directory is the fidelity
backlog - the data the next iteration attacks.

Usage:
  python tests/corpus/corpus_run.py                 # both corpora + triage
  python tests/corpus/corpus_run.py --set=real      # one corpus
  python tests/corpus/corpus_run.py --rebless       # advance every improved gate
  python tests/corpus/corpus_run.py --rebless=real_median   # only the named gate(s)

Reblessing is forward-only per gate: a gate whose measured value would move
its baseline backward is left untouched, so locking one gain no longer drags
the others down. To lower a baseline deliberately, delete it and re-run.
"""

import glob
import json
import os
import shutil
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.join(HERE, "..", ".."))
SYNTH_DOCS = os.path.join(HERE, "docs")
REAL_DOCS = os.path.join(HERE, "real", "docs")
WORK = os.path.join(HERE, "..", "..", "_work", "corpus")
SCORES = os.path.join(HERE, "corpus_scores.json")
BASELINE = os.path.join(HERE, "corpus_baseline.json")
TRIAGE = os.path.join(HERE, "triage")
SZ = (320, 240)
TOL = 0.01


def grey(img):
    from PIL import Image
    return img.convert("L").resize(SZ)


def ssim(a, b):
    pa, pb = a.load(), b.load()
    n = SZ[0] * SZ[1]
    sa = sb = saa = sbb = sab = 0.0
    for y in range(SZ[1]):
        for x in range(SZ[0]):
            va, vb = pa[x, y], pb[x, y]
            sa += va; sb += vb; saa += va * va; sbb += vb * vb; sab += va * vb
    ma, mb = sa / n, sb / n
    va_, vb_ = saa / n - ma * ma, sbb / n - mb * mb
    cov = sab / n - ma * mb
    c1, c2 = (0.01 * 255) ** 2, (0.03 * 255) ** 2
    return ((2 * ma * mb + c1) * (2 * cov + c2)) / ((ma * ma + mb * mb + c1) * (va_ + vb_ + c2))


def diff_regions(src_img, out_img):
    """Describe where two page renders differ: split into a 4x4 grid, score
    each cell by mean absolute difference, name the worst cells."""
    pa, pb = src_img.load(), out_img.load()
    gw, gh = SZ[0] // 4, SZ[1] // 4
    cells = []
    for gy in range(4):
        for gx in range(4):
            s = 0
            for y in range(gy * gh, (gy + 1) * gh, 2):
                for x in range(gx * gw, (gx + 1) * gw, 2):
                    s += abs(pa[x, y] - pb[x, y])
            cells.append((s / ((gw // 2) * (gh // 2)), gx, gy))
    cells.sort(reverse=True)
    names_x = ["left", "centre-left", "centre-right", "right"]
    names_y = ["top", "upper-middle", "lower-middle", "bottom"]
    out = []
    for mad, gx, gy in cells[:3]:
        if mad < 8:  # a quiet cell is not a differing region
            continue
        out.append({"region": f"{names_y[gy]} {names_x[gx]}", "mean_abs_diff": round(mad, 1)})
    return out


def convert_all(eng, pdfs, workdir):
    os.makedirs(workdir, exist_ok=True)
    for i, src in enumerate(pdfs):
        name = os.path.splitext(os.path.basename(src))[0]
        out = os.path.join(workdir, name + ".pptx")
        if os.path.exists(out):
            continue
        try:
            eng.convert(src, out)
        except Exception as e:
            print(f"  CONVERT FAIL {name}: {type(e).__name__}")
        if (i + 1) % 20 == 0:
            print(f"  converted {i + 1}/{len(pdfs)}")


def render_all(app, pdfs, workdir):
    for src in pdfs:
        name = os.path.splitext(os.path.basename(src))[0]
        pptx = os.path.join(workdir, name + ".pptx")
        outdir = os.path.join(workdir, name + "_png")
        if not os.path.exists(pptx) or os.path.isdir(outdir):
            continue
        try:
            pres = app.Presentations.Open(os.path.abspath(pptx), ReadOnly=True,
                                          Untitled=False, WithWindow=False)
            try:
                pres.SaveAs(os.path.abspath(outdir), 18)
            finally:
                pres.Close()
        except Exception as e:
            print(f"  RENDER FAIL {name}: {type(e).__name__}")


def score_all(pdfs, workdir):
    import fitz
    from PIL import Image
    scores = {}
    for src in pdfs:
        name = os.path.splitext(os.path.basename(src))[0]
        outdir = os.path.join(workdir, name + "_png")
        if not os.path.isdir(outdir):
            scores[name] = {"pages": [], "mean": 0.0, "error": "no output"}
            continue
        pngs = sorted(glob.glob(os.path.join(outdir, "*.PNG")) +
                      glob.glob(os.path.join(outdir, "*.png")))
        seen = {os.path.normcase(f): f for f in pngs}
        pngs = sorted(seen.values(), key=lambda f: int("".join(c for c in os.path.basename(f) if c.isdigit()) or 0))
        doc = fitz.open(src)
        page_scores = []
        for i in range(min(doc.page_count, len(pngs))):
            pix = doc[i].get_pixmap(matrix=fitz.Matrix(1.2, 1.2), alpha=False)
            src_img = grey(Image.frombytes("RGB", (pix.width, pix.height), pix.samples))
            out_img = grey(Image.open(pngs[i]))
            page_scores.append(round(ssim(src_img, out_img), 4))
        doc.close()
        scores[name] = {"pages": page_scores,
                        "mean": round(sum(page_scores) / len(page_scores), 4) if page_scores else 0.0}
    return scores


def median_of(scores):
    means = sorted(s["mean"] for s in scores.values())
    return means[len(means) // 2] if means else 0.0


def worst_pages(all_scores, n=10):
    """(score, corpus, doc, page_index) for the n lowest-scoring pages."""
    pages = []
    for corpus, scores in all_scores.items():
        for name, s in scores.items():
            for i, ps in enumerate(s.get("pages", [])):
                pages.append((ps, corpus, name, i))
    pages.sort()
    return pages[:n]


def write_triage(all_scores, workdirs, docdirs):
    """Side-by-side PNGs + notes for the lowest-scoring pages."""
    import fitz
    from PIL import Image
    if os.path.isdir(TRIAGE):
        shutil.rmtree(TRIAGE)
    os.makedirs(TRIAGE, exist_ok=True)
    notes = []
    for rank, (score, corpus, name, pidx) in enumerate(worst_pages(all_scores), 1):
        src = os.path.join(docdirs[corpus], name + ".pdf")
        outdir = os.path.join(workdirs[corpus], name + "_png")
        pngs = sorted(glob.glob(os.path.join(outdir, "*.PNG")) +
                      glob.glob(os.path.join(outdir, "*.png")))
        seen = {os.path.normcase(f): f for f in pngs}
        pngs = sorted(seen.values(), key=lambda f: int("".join(c for c in os.path.basename(f) if c.isdigit()) or 0))
        if pidx >= len(pngs) or not os.path.exists(src):
            continue
        doc = fitz.open(src)
        pix = doc[pidx].get_pixmap(matrix=fitz.Matrix(1.2, 1.2), alpha=False)
        src_img = Image.frombytes("RGB", (pix.width, pix.height), pix.samples)
        doc.close()
        out_img = Image.open(pngs[pidx]).convert("RGB")
        h = 700
        s1 = src_img.resize((int(src_img.width * h / src_img.height), h))
        s2 = out_img.resize((int(out_img.width * h / out_img.height), h))
        combo = Image.new("RGB", (s1.width + s2.width + 12, h), (200, 40, 40))
        combo.paste(s1, (0, 0))
        combo.paste(s2, (s1.width + 12, 0))
        fname = f"{rank:02d}_{corpus}_{name}_p{pidx + 1}.png"
        combo.save(os.path.join(TRIAGE, fname))
        regions = diff_regions(grey(src_img), grey(out_img))
        notes.append({"rank": rank, "corpus": corpus, "doc": name, "page": pidx + 1,
                      "score": score, "image": fname, "differing_regions": regions})
    json.dump(notes, open(os.path.join(TRIAGE, "triage.json"), "w"), indent=1)
    print(f"\ntriage: {len(notes)} worst pages written to {os.path.relpath(TRIAGE, HERE)}/")
    for n in notes:
        regs = "; ".join(f"{r['region']} (mad {r['mean_abs_diff']})" for r in n["differing_regions"]) or "diffuse"
        print(f"  #{n['rank']:02d} {n['score']:.4f} {n['corpus']}/{n['doc']} p{n['page']}: {regs}")


def main():
    import win32com.client
    from tests.engines import ENGINES

    sel = "both"
    for a in sys.argv:
        if a.startswith("--set="):
            sel = a.split("=", 1)[1]
    # --rebless           accept every improved gate as the new baseline
    # --rebless=real_median,worst_page_floor   only the named gates
    # Reblessing is forward-only per gate (the SITE_SPEC rule): a gate whose
    # measured value would move its baseline BACKWARD is left untouched, so a
    # change that lifts one gate can no longer drag the others down with it.
    rebless = None
    for a in sys.argv:
        if a == "--rebless":
            rebless = "ALL"
        elif a.startswith("--rebless="):
            rebless = {t.strip() for t in a.split("=", 1)[1].split(",") if t.strip()}

    corpora = {}
    if sel in ("both", "synthetic"):
        corpora["synthetic"] = SYNTH_DOCS
    if sel in ("both", "real"):
        corpora["real"] = REAL_DOCS

    eng = ENGINES["browser"]
    workdirs = {c: os.path.join(WORK, c) for c in corpora}
    pdf_sets = {c: sorted(glob.glob(os.path.join(d, "*.pdf"))) for c, d in corpora.items()}

    for c, pdfs in pdf_sets.items():
        print(f"corpus run [{c}]: {len(pdfs)} documents")
        convert_all(eng, pdfs, workdirs[c])

    app = win32com.client.Dispatch("PowerPoint.Application")
    try:
        for c, pdfs in pdf_sets.items():
            render_all(app, pdfs, workdirs[c])
    finally:
        app.Quit()

    all_scores = {c: score_all(pdfs, workdirs[c]) for c, pdfs in pdf_sets.items()}

    result = {}
    for c, scores in all_scores.items():
        med = median_of(scores)
        result[c + "_median"] = med
        result[c] = scores
        print(f"\n[{c}] median SSIM: {med:.4f} over {len(scores)} documents")
        worst = sorted(scores.items(), key=lambda kv: kv[1]["mean"])[:10]
        print(f"[{c}] 10 worst documents:")
        for name, s in worst:
            print(f"  {s['mean']:.4f}  {name}  {s.get('error', '')}")

    wp = worst_pages(all_scores, 1)
    floor = wp[0][0] if wp else 0.0
    result["worst_page_floor"] = floor
    print(f"\nworst-page floor: {floor:.4f}"
          + (f" ({wp[0][1]}/{wp[0][2]} p{wp[0][3] + 1})" if wp else ""))
    json.dump(result, open(SCORES, "w"), indent=1)

    docdirs = dict(corpora)
    write_triage(all_scores, workdirs, docdirs)

    # ---- gate against the baseline ----
    gates = {k: result[k] for k in result if k.endswith("_median")}
    # worst_page_floor is the single lowest page across BOTH corpora; a
    # partial run (--set) sees only some pages, so its floor is not comparable
    # and must never be gated or reblessed from one.
    if sel == "both":
        gates["worst_page_floor"] = floor

    if not os.path.exists(BASELINE):
        json.dump(gates, open(BASELINE, "w"), indent=1)
        print("baseline written:", {k: round(v, 4) for k, v in gates.items()})
        return 0
    base = json.load(open(BASELINE))

    if rebless is not None:
        targets = set(gates) if rebless == "ALL" else rebless
        for k in sorted(targets):
            if k not in gates:
                print(f"skipped {k}: not measured in this run")
                continue
            v, b = gates[k], base.get(k)
            if b is None:
                base[k] = v
                print(f"reblessed {k}: (new) -> {v:.4f}")
            elif v > b:
                base[k] = v
                print(f"reblessed {k}: {b:.4f} -> {v:.4f}")
            else:
                print(f"kept {k}: {b:.4f} (measured {v:.4f} would move backward; "
                      f"baselines only move forward)")
        json.dump(base, open(BASELINE, "w"), indent=1)
        return 0

    failed = False
    for k, v in gates.items():
        b = base.get(k)
        if b is None:
            base[k] = v   # a gate measured for the first time becomes baseline
            print(f"gate {k}: {v:.4f} (new, added to baseline)")
            continue
        if v < b - TOL:
            print(f"REGRESSION: {k} {v:.4f} vs baseline {b:.4f}")
            failed = True
        else:
            print(f"gate {k}: {v:.4f} vs baseline {b:.4f}: OK")
    json.dump(base, open(BASELINE, "w"), indent=1)
    return 1 if failed else 0


if __name__ == "__main__":
    sys.exit(main())
